output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?species ?speciesLabel ?lifeExpectancy ?bodyMass WHERE {
  ?species wdt:P105 wd:Q729 .
  ?species wdt:P171 + wd:Q25324 .
  ?species rdfs:label ?speciesLabel .
  FILTER(LANG(?speciesLabel) = "en")
  OPTIONAL {
    ?species wdt:P2250 ?lifeExpectancy
  }
  OPTIONAL {
    ?species wdt:P2067 ?bodyMass
  }
}
ORDER BY ?speciesLabel
